import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"知识产权保护与防伪打假指南","description":"","frontmatter":{},"headers":[],"relativePath":"zh/ip-guide.md","filePath":"zh/ip-guide.md"}'),h={name:"zh/ip-guide.md"};function i(l,t,o,n,b,P){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="知识产权保护与防伪打假指南" tabindex="-1">知识产权保护与防伪打假指南 <a class="header-anchor" href="#知识产权保护与防伪打假指南" aria-label="Permalink to &quot;知识产权保护与防伪打假指南&quot;">​</a></h1><h1 id="知识产权保护与防伪打假指南-1" tabindex="-1">知识产权保护与防伪打假指南 <a class="header-anchor" href="#知识产权保护与防伪打假指南-1" aria-label="Permalink to &quot;知识产权保护与防伪打假指南&quot;">​</a></h1><p><em>Intellectual Property Protection &amp; Anti-Counterfeiting</em><em>Supply Chain Due Diligence Guide</em></p><p>2025年版　　适用范围：制造业、零售业、电商平台及品牌持有人</p><h1 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h1><p>假冒伪劣商品已成为全球供应链面临的最严峻威胁之一。根据经济合作与发展组织（OECD）与欧盟知识产权局（EUIPO）联合发布的报告，全球假冒品贸易规模已达5,090亿美元，占全球贸易总量的2.5%。假冒商品不仅侵蚀品牌价值、压缩利润空间，更可能直接威胁消费者安全——尤其在汽车零部件、医疗器械、儿童玩具、航空航天零件等高风险领域。 与此同时，企业的知识产权（IP）资产日益集中于供应链的各个环节：制造商掌握制造工艺，代工厂接触核心配方，分销商持有品牌授权，贸易商传递市场反馈。每一个供应链节点，都可能成为IP泄露和假冒渗透的入口。 本指南是《供应链尽责管理系列》的组成部分，聚焦知识产权保护与防伪打假的供应链尽职调查实操，覆盖：</p><ul><li>品牌商标、专利与商业秘密在供应链中的保护策略</li><li>防伪技术的选择与部署（明标、暗标、数字防伪）</li><li>海关备案与跨境执法协作机制</li><li>线上渠道监控与平台治理</li><li>IP尽职调查审核方法论与评分框架</li><li>适用于各类供应商的检查清单 本指南适用于品牌持有人、采购团队、知识产权/法务部门、合规审核人员，以及供应链中下游供应商的合规管理人员。 <em>阅读提示：本指南是《供应链尽责管理系列》的组成部分，建议与系列内其他指南结合使用。</em></li></ul><h1 id="第一章-知识产权基础-供应链视角" tabindex="-1">第一章　知识产权基础：供应链视角 <a class="header-anchor" href="#第一章-知识产权基础-供应链视角" aria-label="Permalink to &quot;第一章　知识产权基础：供应链视角&quot;">​</a></h1><h2 id="_1-1-ip资产类型与供应链风险映射" tabindex="-1">1.1　IP资产类型与供应链风险映射 <a class="header-anchor" href="#_1-1-ip资产类型与供应链风险映射" aria-label="Permalink to &quot;1.1　IP资产类型与供应链风险映射&quot;">​</a></h2><p>知识产权保护在供应链中的挑战，在于IP资产的无形性与供应链链条的复杂性之间的张力。品牌持有人通常能管控最终产品，却难以管控中间制造环节中IP资产的使用方式。下表梳理了主要IP类型及其在供应链各层级的典型风险。</p><table tabindex="0"><thead><tr><th>IP类型</th><th>核心内容</th><th>供应链层级风险</th><th>主要法律依据</th></tr></thead><tbody><tr><td>商标 （Trademark）</td><td>商品/服务来源标识；注册商标受法律保护，未注册商标依赖使用证明</td><td>T1代工厂：未经授权贴牌；分销商：平行进口/灰色市场；电商：仿冒店铺</td><td>《商标法》（中国） Trademark Act（美） EU Trademark Regulation</td></tr><tr><td>专利 （Patent）</td><td>发明专利（20年）/实用新型（10年）/外观设计（15年）；公开换保护</td><td>T2供应商：侵权制造工艺；代工厂：向第三方披露受专利保护的设计</td><td>《专利法》（中国） Patent Act（美） EPC（欧洲）</td></tr><tr><td>版权 （Copyright）</td><td>作品自动产生；无须注册；含软件源代码、CAD图纸、用户手册</td><td>代工厂：未经授权复制设计文件；ODM供应商：归属权争议</td><td>《著作权法》（中国） Copyright Act（美） Berne Convention</td></tr><tr><td>商业秘密 （Trade Secret）</td><td>不公开、有价值、采取保密措施的信息；无期限保护</td><td>所有层级均面临：员工跳槽带走配方/工艺；供应商与竞争对手共享平台</td><td>《反不正当竞争法》（中国） DTSA（美） EU Trade Secrets Directive</td></tr><tr><td>外观设计 （Design Right）</td><td>产品外观、形状、图案；注册外观设计保护期更长</td><td>仿冒品往往以「近似外观」规避注册设计保护</td><td>《专利法》外观设计章（中国） EU Design Regulation</td></tr><tr><td>地理标志 （GI）</td><td>来源地与品质关联；葡萄酒/食品/茶叶等高度相关</td><td>原产地造假；成分替换；「搭便车」包装</td><td>《地理标志保护产品》GB/T 17924（中国） EU GI Regulation</td></tr></tbody></table><h2 id="_1-2-假冒品供应链的运作逻辑" tabindex="-1">1.2　假冒品供应链的运作逻辑 <a class="header-anchor" href="#_1-2-假冒品供应链的运作逻辑" aria-label="Permalink to &quot;1.2　假冒品供应链的运作逻辑&quot;">​</a></h2><p>理解假冒品如何渗透供应链，是构建有效防控体系的前提。假冒品供应链并非随机事件，而是遵循特定的经济逻辑和运作模式。</p><h2 id="_1-2-1-假冒品的四种渗透路径" tabindex="-1">1.2.1　假冒品的四种渗透路径 <a class="header-anchor" href="#_1-2-1-假冒品的四种渗透路径" aria-label="Permalink to &quot;1.2.1　假冒品的四种渗透路径&quot;">​</a></h2><table tabindex="0"><thead><tr><th>渗透路径</th><th>运作方式</th><th>典型行业</th><th>识别难度</th></tr></thead><tbody><tr><td>超产走私 （Overrun）</td><td>授权代工厂在正常订单之外超产，利用同等原材料/模具生产「真品同款」假冒品</td><td>服装、运动鞋、电子消费品</td><td>★★★★ 外观与真品完全一致</td></tr><tr><td>平行进口 （Gray Market）</td><td>真品通过未授权渠道流通，绕过品牌商的定价体系和区域授权</td><td>奢侈品、汽车配件、医药</td><td>★★★ 产品本身为真，渠道违规</td></tr><tr><td>近似仿冒 （Knockoff）</td><td>模仿外观、包装、颜色、字体，但刻意与注册商标保持「一字之差」</td><td>快消品、化妆品、日用品</td><td>★★ 仔细检查可辨</td></tr><tr><td>全仿品 （Counterfeit）</td><td>全面复制商标、包装、防伪标识，意图混入正品渠道</td><td>药品、汽配、航空零件、食品</td><td>★★★★★ 可能通过常规抽检</td></tr></tbody></table><h2 id="_1-2-2-假冒品风险的行业分布" tabindex="-1">1.2.2　假冒品风险的行业分布 <a class="header-anchor" href="#_1-2-2-假冒品风险的行业分布" aria-label="Permalink to &quot;1.2.2　假冒品风险的行业分布&quot;">​</a></h2><p>并非所有行业面临同等假冒风险。下列因素决定一个品牌或产品类别的假冒吸引力：</p><ul><li>品牌溢价高：消费者愿意为品牌支付超出成本的溢价，使仿冒利润丰厚</li><li>产品可识别性强：标志、字体、配色具有高辨识度，易于复制</li><li>安全监管要求高：药品、汽配等监管门槛高，但也意味着假冒可获暴利</li><li>供应链层级深、地理分散：T3/T4供应商所在地区执法能力薄弱</li><li>数字销售渠道占比高：电商平台入驻门槛低，假冒品上架成本极低</li></ul><table tabindex="0"><thead><tr><th>行业</th><th>主要假冒形式</th><th>安全风险</th><th>代表性事件/数据</th></tr></thead><tbody><tr><td>汽车配件</td><td>刹车片、安全气囊、转向零件仿冒</td><td>★★★★★ 直接危及生命</td><td>OECD：全球汽配假冒品年贸易额超450亿美元</td></tr><tr><td>药品/医疗器械</td><td>包装复制、成分替换、有效期篡改</td><td>★★★★★ 用药安全风险</td><td>WHO：低收入国家10%的药品为假冒</td></tr><tr><td>电子消费品</td><td>充电器、电池、耳机仿冒</td><td>★★★★ 电气安全、数据安全</td><td>IEC：假冒充电器致人身伤害案例逐年上升</td></tr><tr><td>奢侈品/服装</td><td>外观仿冒、超产走私、灰色市场</td><td>★★ 品牌价值损失</td><td>EUIPO：EU消费者年均损失约600亿欧元</td></tr><tr><td>食品/饮料</td><td>原产地造假、成分替换、包装仿冒</td><td>★★★★ 食品安全风险</td><td>橄榄油、蜂蜜、葡萄酒为高频假冒品类</td></tr><tr><td>航空航天零件</td><td>螺栓、紧固件、传感器仿冒</td><td>★★★★★ 飞行安全风险</td><td>FAA：每年查获数万个疑似假冒航材</td></tr><tr><td>农化/种子</td><td>农药有效成分稀释、种子品种替换</td><td>★★★★ 农业减产、环境污染</td><td>亚洲市场农药假冒率在部分品类超30%</td></tr></tbody></table><p><em>图1-1　全球假冒品贸易规模按行业分布（数据来源：OECD/EUIPO 2022年报告，约值）</em></p><h2 id="_1-3-法律责任框架-企业需要了解什么" tabindex="-1">1.3　法律责任框架：企业需要了解什么 <a class="header-anchor" href="#_1-3-法律责任框架-企业需要了解什么" aria-label="Permalink to &quot;1.3　法律责任框架：企业需要了解什么&quot;">​</a></h2><p>知识产权侵权的法律后果正在全球范围内持续加重。企业不仅需要保护自身IP，还需确保其供应链活动不构成对他人IP的侵权。</p><h2 id="_1-3-1-中国法律框架" tabindex="-1">1.3.1　中国法律框架 <a class="header-anchor" href="#_1-3-1-中国法律框架" aria-label="Permalink to &quot;1.3.1　中国法律框架&quot;">​</a></h2><ul><li>《商标法》（2019年修订）：引入惩罚性赔偿，侵权赔偿最高可达实际损失的5倍；将恶意侵权纳入刑事追诉范围</li><li>《专利法》（2021年修订）：惩罚性赔偿上限从3倍提升至5倍；设立国家知识产权局专利侵权纠纷行政裁决机制</li><li>《反不正当竞争法》（2019年修订）：商业秘密侵权赔偿上限500万元；明确&quot;获取、披露、使用、允许他人使用&quot;均构成侵权</li><li>《刑法》第213-220条：假冒注册商标罪最高处7年有期徒刑；非法制造注册商标标识罪亦可追究刑事责任</li><li>《海关知识产权保护条例》：权利人可向海关总署备案，申请扣押疑似侵权货物</li></ul><h2 id="_1-3-2-主要国际框架" tabindex="-1">1.3.2　主要国际框架 <a class="header-anchor" href="#_1-3-2-主要国际框架" aria-label="Permalink to &quot;1.3.2　主要国际框架&quot;">​</a></h2><table tabindex="0"><thead><tr><th>法律/公约</th><th>管辖范围</th><th>核心义务/处罚</th><th>供应链关联度</th></tr></thead><tbody><tr><td>TRIPS协定 （WTO）</td><td>WTO所有成员国</td><td>最低IP保护标准；边境措施义务；刑事追诉标准</td><td>★★★★ 中国/欧美均为成员，跨境执法基础</td></tr><tr><td>美国Lanham Act （商标法）</td><td>美国境内及涉美贸易</td><td>法定赔偿每件商标侵权最高200万美元（恶意）</td><td>★★★★★ 出口美国的供应商需重点关注</td></tr><tr><td>美国DTSA （商业秘密保护法）</td><td>美国联邦层级</td><td>可获得禁令、损害赔偿；扣押令针对商业秘密窃取</td><td>★★★★ 中美供应链转移中的核心风险</td></tr><tr><td>EU商标条例 （EUTMR）</td><td>欧盟27国</td><td>单一注册覆盖全境；过境扣押（in-transit seizure）权</td><td>★★★★★ 过境扣押对中国出口影响大</td></tr><tr><td>UK知识产权法</td><td>英国（脱欧后独立体系）</td><td>刑事罚款无上限；TM Eye等私人执法机构活跃</td><td>★★★ 英国市场进入须单独备案</td></tr></tbody></table><h1 id="第二章-商标保护与品牌安全" tabindex="-1">第二章　商标保护与品牌安全 <a class="header-anchor" href="#第二章-商标保护与品牌安全" aria-label="Permalink to &quot;第二章　商标保护与品牌安全&quot;">​</a></h1><h2 id="_2-1-商标注册策略-供应链布局维度" tabindex="-1">2.1　商标注册策略：供应链布局维度 <a class="header-anchor" href="#_2-1-商标注册策略-供应链布局维度" aria-label="Permalink to &quot;2.1　商标注册策略：供应链布局维度&quot;">​</a></h2><p>商标注册本身是一项商业决策，而非单纯的法律动作。在供应链背景下，注册策略需要覆盖两个维度：地理范围（产品销售/制造所在的所有司法管辖区）和类别范围（防止抢注和近似类别攀附）。</p><h2 id="_2-1-1-注册地图-供应链关键司法管辖区" tabindex="-1">2.1.1　注册地图：供应链关键司法管辖区 <a class="header-anchor" href="#_2-1-1-注册地图-供应链关键司法管辖区" aria-label="Permalink to &quot;2.1.1　注册地图：供应链关键司法管辖区&quot;">​</a></h2><table tabindex="0"><thead><tr><th>司法管辖区</th><th>注册途径</th><th>审查周期</th><th>注意事项</th></tr></thead><tbody><tr><td>中国</td><td>国家知识产权局（CNIPA）直接申请；或通过马德里体系指定中国</td><td>约12-18个月（含公告期）</td><td>商标抢注风险极高；建议在制造商/供应商开始合作前完成注册；「防御性商标」（近似类别）值得考虑</td></tr><tr><td>欧盟（EUTM）</td><td>欧盟知识产权局（EUIPO）单一申请覆盖27国</td><td>约4-6个月（无异议）</td><td>一国异议可阻断整个EUTM；考虑对高风险国家单独提交</td></tr><tr><td>美国</td><td>USPTO直接申请；使用在先原则（Use in Commerce）</td><td>约8-12个月</td><td>需证明商业使用；Section 15声明可获不可争议地位（5年后）</td></tr><tr><td>东南亚重点国家</td><td>越南、泰国、印尼、马来西亚各自申请（非共同体）</td><td>越南12-18月；泰国12月；印尼24-36月</td><td>制造业外包重点国家；建议在T1供应商所在国优先注册</td></tr><tr><td>马德里体系 （国际注册）</td><td>通过WIPO一次申请指定多国（113个成员国）</td><td>取决于指定国；18个月审查窗口</td><td>基础申请遭撤销可导致「中央攻击」；建议组合使用</td></tr></tbody></table><h2 id="_2-1-2-类别覆盖策略" tabindex="-1">2.1.2　类别覆盖策略 <a class="header-anchor" href="#_2-1-2-类别覆盖策略" aria-label="Permalink to &quot;2.1.2　类别覆盖策略&quot;">​</a></h2><p>仅注册核心产品类别是不够的。供应链中的假冒风险往往来自「近似类别」——攻击者在相邻类别抢注，再以近似混淆为由向品牌持有人索赔或阻止其扩张。建议策略：</p><ul><li>核心类别（必须注册）：产品直接涉及的Nice分类类别</li><li>防御类别（建议注册）：与核心类别在消费者心智中具有关联性的类别；电商平台（如Class 35在线零售服务）</li><li>企业名称注册：在中国，企业名称与商标是不同的注册体系，二者均需保护</li><li>域名注册：与商标一致的主流顶级域名（.com、.cn、.eu等），防止网络钓鱼和仿冒网站</li></ul><h2 id="_2-2-授权管理-供应商商标使用控制" tabindex="-1">2.2　授权管理：供应商商标使用控制 <a class="header-anchor" href="#_2-2-授权管理-供应商商标使用控制" aria-label="Permalink to &quot;2.2　授权管理：供应商商标使用控制&quot;">​</a></h2><p>在代工生产（OEM）和合同制造（CM）模式下，供应商通常需要在生产过程中使用品牌持有人的商标（在产品上贴牌）。如果这一使用权未经严格管控，将产生以下风险：</p><ul><li>超产风险：供应商利用授权使用权超产并向第三方销售，产生「超产走私」假冒品</li><li>商标转让风险：部分国家允许通过持续使用建立商标权，供应商可能主张独立商标权</li><li>二次许可风险：供应商擅自将商标使用权转许可给分包商，品牌持有人失去管控</li></ul><h2 id="_2-2-1-供应商商标使用授权协议要素" tabindex="-1">2.2.1　供应商商标使用授权协议要素 <a class="header-anchor" href="#_2-2-1-供应商商标使用授权协议要素" aria-label="Permalink to &quot;2.2.1　供应商商标使用授权协议要素&quot;">​</a></h2><p><em>以下要素应纳入与代工/OEM/CM供应商的合同或单独的商标授权协议（Trademark License Agreement, TLA）中，而非仅依赖采购订单条款。</em></p><ul><li>授权范围明确化：明确列出被许可使用的商标（注册号/图样）、授权用途（仅用于执行本采购订单项下产品的生产贴标）、使用媒介（产品本体/包装/运输标签）</li><li>禁止转许可：明确禁止供应商将商标使用权转让或再许可给任何第三方（含分包商）</li><li>产量核对权：品牌持有人有权要求供应商提供原材料采购量与成品出货量的对账记录，用于核查超产</li><li>模具与工装所有权：明确品牌专属模具（用于生产带有品牌标识的产品）的所有权归属于品牌持有人，供应商无权另行使用</li><li>终止后义务：合同终止后，供应商须立即停止使用商标，销毁所有带有商标的库存（品牌持有人可选择回购），并向品牌持有人提供销毁证明</li><li>审计权：品牌持有人有权（预约或突击）审计供应商的生产记录、库存台账和运输文件</li></ul><h2 id="_2-3-灰色市场管理" tabindex="-1">2.3　灰色市场管理 <a class="header-anchor" href="#_2-3-灰色市场管理" aria-label="Permalink to &quot;2.3　灰色市场管理&quot;">​</a></h2><p>灰色市场（平行进口）是指真品通过未经授权的渠道流通，绕过品牌持有人的区域定价和分销体系。灰色市场本身并非造假，但会侵蚀品牌溢价、破坏区域定价体系，并可能因售后服务缺位（如非本地版本不提供官方保修）对消费者产生伤害。</p><h2 id="_2-3-1-灰色市场的供应链来源" tabindex="-1">2.3.1　灰色市场的供应链来源 <a class="header-anchor" href="#_2-3-1-灰色市场的供应链来源" aria-label="Permalink to &quot;2.3.1　灰色市场的供应链来源&quot;">​</a></h2><table tabindex="0"><thead><tr><th>来源</th><th>产生机制</th><th>管控措施</th></tr></thead><tbody><tr><td>区域差价套利</td><td>不同市场同款产品存在较大价差，贸易商低价采购后转销高价市场</td><td>区域差异化包装/产品编号；合同中明确授权销售区域限制</td></tr><tr><td>经销商超量采购</td><td>经销商拿到大单折扣后，将超额库存通过非官方渠道清货</td><td>经销商协议中设定最低/最高采购量；终止条款明确灰市处罚</td></tr><tr><td>超产走私</td><td>见2.2节——供应商超出订单量生产，产品流入未授权渠道</td><td>产量审计；模具管控；原材料管理</td></tr><tr><td>退货品再销售</td><td>消费者退货品被再包装后作为新品销售</td><td>退货产品标识系统；授权返工流程</td></tr><tr><td>过期/临近到期品</td><td>接近保质期产品以低价进入未授权渠道（食品/化妆品/药品）</td><td>序列号追踪；到期日管理；定期渠道清查</td></tr></tbody></table><h2 id="_2-4-品牌监控-主动发现侵权" tabindex="-1">2.4　品牌监控：主动发现侵权 <a class="header-anchor" href="#_2-4-品牌监控-主动发现侵权" aria-label="Permalink to &quot;2.4　品牌监控：主动发现侵权&quot;">​</a></h2><p>被动等待举报已无法应对当前假冒品的扩散速度。品牌持有人需要建立主动监控体系，在侵权行为成规模之前发现并处置。</p><h2 id="_2-4-1-监控维度与工具" tabindex="-1">2.4.1　监控维度与工具 <a class="header-anchor" href="#_2-4-1-监控维度与工具" aria-label="Permalink to &quot;2.4.1　监控维度与工具&quot;">​</a></h2><table tabindex="0"><thead><tr><th>监控维度</th><th>监控内容</th><th>推荐工具/方法</th></tr></thead><tbody><tr><td>商标注册监控</td><td>全球商标局新申请中，监控与自有商标近似的新申请</td><td>WIPO Global Brand Database；CNIPA商标网；专业IP监控服务（Corsearch, Clarivate）</td></tr><tr><td>电商平台监控</td><td>淘宝/天猫、京东、Amazon、eBay、Shopee、Lazada等平台上的仿冒品列表</td><td>Brand Protection服务（Amazon BP、Alibaba IPP）；第三方品牌保护平台（Red Points、MarkMonitor）</td></tr><tr><td>社交媒体监控</td><td>微信/微博/抖音/Instagram/Facebook上的仿冒品推广</td><td>关键词监控；图像识别AI；平台举报机制</td></tr><tr><td>域名监控</td><td>新注册与品牌相似的域名（typosquatting、cybersquatting）</td><td>DMARC/phishing监控；域名注册预警服务</td></tr><tr><td>实体市场监控</td><td>批发市场、小商品市场（义乌、广州等）的定期巡查</td><td>本地调查公司；行业协会联合监控</td></tr><tr><td>供应链内部监控</td><td>供应商超产、平行出货的早期信号</td><td>原材料与产成品数量比对；物流数据交叉核查</td></tr></tbody></table><h1 id="第三章-专利与商业秘密供应链保护" tabindex="-1">第三章　专利与商业秘密供应链保护 <a class="header-anchor" href="#第三章-专利与商业秘密供应链保护" aria-label="Permalink to &quot;第三章　专利与商业秘密供应链保护&quot;">​</a></h1><h2 id="_3-1-专利布局的供应链策略" tabindex="-1">3.1　专利布局的供应链策略 <a class="header-anchor" href="#_3-1-专利布局的供应链策略" aria-label="Permalink to &quot;3.1　专利布局的供应链策略&quot;">​</a></h2><p>专利保护的供应链策略与商标有所不同：专利通过公开换取保护，一旦授权便成为可执行的权利；但专利申请是公开的，竞争对手和供应商均可研究专利布局，找出「设计规避」（design-around）空间。</p><h2 id="_3-1-1-专利组合的供应链考量" tabindex="-1">3.1.1　专利组合的供应链考量 <a class="header-anchor" href="#_3-1-1-专利组合的供应链考量" aria-label="Permalink to &quot;3.1.1　专利组合的供应链考量&quot;">​</a></h2><ul><li>制造方法专利：保护「如何制造」而非仅保护产品本身；供应商在制造过程中可能侵犯方法专利，即便最终产品未含受保护结构</li><li>外观设计专利：对于高仿品最直接的法律工具；应覆盖产品在不同角度的外观；中国外观设计专利审查快（通常3-6个月），是快速维权的首选路径</li><li>实用新型专利（中国特有）：审查快（约6个月）、保护期10年；适合对供应链常用工艺/零部件的快速布局</li><li>专利地图（Patent Landscape）：定期分析竞争对手和供应商的专利申请，发现技术转移信号和侵权风险</li></ul><h2 id="_3-2-商业秘密-供应链中最难保护的ip资产" tabindex="-1">3.2　商业秘密：供应链中最难保护的IP资产 <a class="header-anchor" href="#_3-2-商业秘密-供应链中最难保护的ip资产" aria-label="Permalink to &quot;3.2　商业秘密：供应链中最难保护的IP资产&quot;">​</a></h2><p>商业秘密（Trade Secret）是供应链中最普遍、最难管控的IP资产类型。与专利不同，商业秘密不需要注册，但保护的前提是企业能够证明：（1）信息具有商业价值；（2）信息处于保密状态；（3）企业采取了合理的保密措施。在供应链中，每一次向供应商披露工艺、配方、技术参数，都是一次潜在的泄露机会。</p><h2 id="_3-2-1-商业秘密在供应链中的泄露路径" tabindex="-1">3.2.1　商业秘密在供应链中的泄露路径 <a class="header-anchor" href="#_3-2-1-商业秘密在供应链中的泄露路径" aria-label="Permalink to &quot;3.2.1　商业秘密在供应链中的泄露路径&quot;">​</a></h2><table tabindex="0"><thead><tr><th>泄露路径</th><th>典型场景</th><th>防控措施</th></tr></thead><tbody><tr><td>员工流动</td><td>供应商员工离职，携带含核心工艺信息的文件或记忆加入竞争对手</td><td>竞业限制协议（NCA）；离职访谈；知识隔离（Compartmentalization）</td></tr><tr><td>供应商共享平台</td><td>供应商同时服务多个竞争对手，在系统中存储来自不同客户的技术文件</td><td>独立项目空间（无法跨客户访问）；云端数据室权限管理</td></tr><tr><td>分包与转包</td><td>供应商将订单转包，分包商获取到不应接触的技术文件</td><td>合同明确禁止转包；技术文件按需最小化披露</td></tr><tr><td>逆向工程</td><td>供应商/竞争对手通过拆解产品反推工艺参数</td><td>产品设计中引入「阶梯式保护」（核心工艺不体现在产品上）；追溯性侵权诉讼</td></tr><tr><td>数字入侵</td><td>供应商系统被攻击，企业上传至供应商平台的技术文件被窃取</td><td>文件加密传输；VDR（虚拟数据室）；访问日志；IP溯源</td></tr><tr><td>参观/审厂</td><td>访客在工厂参观时拍照/记录；供应商现场审核员携出敏感信息</td><td>明确参观拍照政策；NDA（保密协议）前置；来宾伴同制度</td></tr></tbody></table><details class="details custom-block"><summary>延伸阅读：真实案例——通用电气（GE）航空发动机技术窃密案</summary><p><strong>GE航空涡扇发动机技术间谍案（2018–2022年）</strong>：美国联邦调查局（FBI）起诉前通用电气航空工程师郑晓庆（Xiaoqing Zheng），指控其将GE航空商业秘密——涡扇和涡轮发动机的核心技术文件——窃取并传递给中国竞争对手。郑晓庆使用的手法极为隐蔽：将技术文件藏匿在图形文件（<code>.bmp</code>图片）的元数据（Exif/隐写术）中，通过电子邮件发送，绕过了GE常规的数据防泄露（DLP）系统。2022年，郑晓庆被判处24个月有期徒刑。</p><p><strong>案件揭示的供应链技术保护盲区：</strong></p><ul><li><strong>内部威胁（Insider Threat）比外部攻击更难防范</strong>：郑晓庆是拥有合法访问权限的高级工程师，其行为在DLP系统看来是正常的文件访问和邮件发送。</li><li><strong>隐写术（Steganography）绕过文件内容扫描</strong>：技术文件被隐藏在图像文件中，传统的关键字/内容扫描型DLP无法检测。GE事件后，企业级DLP系统开始加入对图像/文件元数据的深度扫描能力。</li><li><strong>访问日志是关键证据来源</strong>：FBI的调查突破点之一是GE系统保留了完整的文件访问日志，能够追溯郑晓庆在离职前大量集中访问和下载核心文件的异常行为。<strong>日志留存是IP保护的基础设施，而非可选项。</strong></li></ul><p><strong>对供应链的直接启示：</strong> 向供应商披露的技术文件同样适用上述保护逻辑——水印追踪、访问日志、最小权限原则，以及针对文件导出行为的异常监控。</p></details><h2 id="_3-2-2-商业秘密保护的合同要素" tabindex="-1">3.2.2　商业秘密保护的合同要素 <a class="header-anchor" href="#_3-2-2-商业秘密保护的合同要素" aria-label="Permalink to &quot;3.2.2　商业秘密保护的合同要素&quot;">​</a></h2><p><em>以下条款应纳入所有与供应商/合作伙伴签订的保密协议（NDA）或在采购框架协议中专门设置保密章节。</em></p><ul><li>保密信息定义：明确列举或描述受保护信息的范围（技术参数、配方、工艺路线、客户名单、定价模型等），避免过宽或过窄</li><li>保密期限：明确保密义务的有效期；对于商业秘密应约定「存续至该信息进入公共领域为止」而非固定年限</li><li>信息分级：约定信息分级标准（机密/秘密/内部/公开）及各级别的保管要求</li><li>知悉需要原则（Need-to-Know）：接触保密信息的供应商员工须在NDA框架下单独签署保密承诺，且仅限于履行合同所需知悉的信息</li><li>返还与销毁：合同终止后，供应商须在规定期限内（建议30日内）返还或销毁所有保密信息载体，并提供书面证明</li><li>救济措施：明确违反保密义务的救济途径（申请禁令+损害赔偿；选择仲裁还是诉讼）；可约定每次违约的违约金基准</li></ul><h2 id="_3-3-技术文件分级管理" tabindex="-1">3.3　技术文件分级管理 <a class="header-anchor" href="#_3-3-技术文件分级管理" aria-label="Permalink to &quot;3.3　技术文件分级管理&quot;">​</a></h2><table tabindex="0"><thead><tr><th>分级</th><th>典型内容</th><th>向供应商披露原则</th><th>传递方式</th></tr></thead><tbody><tr><td>绝密（TS）</td><td>核心配方、关键算法、10年以上研发积累的工艺参数</td><td>原则上不向外部供应商披露；如必须披露，仅限少数经批准的高信任合作伙伴</td><td>加密传输；禁止打印/复制；水印追踪；访问日志留存≥5年</td></tr><tr><td>机密（C）</td><td>产品设计图纸（含尺寸公差）、详细工艺流程、测试方法</td><td>仅披露给执行特定订单所需的供应商，且限于负责执行该订单的团队成员</td><td>VDR（虚拟数据室）；下载权限须申请；禁止截图</td></tr><tr><td>秘密（S）</td><td>产品规格书、材料清单（BOM）、包装规范</td><td>T1供应商（需执行合同者）；可传递给T2供应商中与材料相关的部分</td><td>加盖保密标记的PDF；禁止二次转发</td></tr><tr><td>内部（I）</td><td>一般商务信息、质量标准、产品认证要求</td><td>可共享给所有相关供应商，但须告知其保密属性</td><td>普通邮件/ERP系统；注明『内部资料，请勿对外分发』</td></tr></tbody></table><h1 id="第四章-防伪技术选择与部署" tabindex="-1">第四章　防伪技术选择与部署 <a class="header-anchor" href="#第四章-防伪技术选择与部署" aria-label="Permalink to &quot;第四章　防伪技术选择与部署&quot;">​</a></h1><h2 id="_4-1-防伪技术分类框架" tabindex="-1">4.1　防伪技术分类框架 <a class="header-anchor" href="#_4-1-防伪技术分类框架" aria-label="Permalink to &quot;4.1　防伪技术分类框架&quot;">​</a></h2><p>防伪技术通常分为三个层次：明标（Overt Features）——消费者可自行识别；暗标（Covert Features）——需要专用工具识别；数字技术（Digital/Track &amp; Trace）——通过数字系统验证。三层防伪相互补充，构成纵深防御体系。单一技术均可被仿制，多层组合才能有效提升仿冒成本。</p><p><em>图4-1　防伪技术综合能力评估雷达图（各维度1=低/差，5=高/强；综合部署建议选2-3层互补技术）</em></p><table tabindex="0"><thead><tr><th>层次</th><th>技术类型</th><th>识别方式</th><th>仿制难度</th><th>单位成本</th><th>适用场景</th></tr></thead><tbody><tr><td>明标 （Overt）</td><td>全息标签（Hologram）</td><td>肉眼（光线变化）</td><td>★★★ 工业级全息可被仿制</td><td>¥0.1-0.5/件</td><td>消费品、票据、证件</td></tr><tr><td>明标 （Overt）</td><td>色移油墨（Color-Shifting Ink）</td><td>倾斜时颜色变化</td><td>★★★★</td><td>包含于印刷成本</td><td>高端包装、证件、货币</td></tr><tr><td>明标 （Overt）</td><td>荧光纤维/微印刷</td><td>需紫外灯；或放大镜查看微型文字</td><td>★★★★</td><td>¥0.05-0.2/件</td><td>药品包装、食品标签</td></tr><tr><td>暗标 （Covert）</td><td>化学标记物（Taggant）</td><td>专用检测仪器（手持式光谱仪）</td><td>★★★★★ 化学成分不公开</td><td>¥0.5-2.0/件</td><td>工业品、汽配、高价值消费品</td></tr><tr><td>暗标 （Covert）</td><td>微点技术（Microdot）</td><td>显微镜+专用阅读设备</td><td>★★★★★</td><td>¥0.2-1.0/件</td><td>精密零件、汽配</td></tr><tr><td>数字 （Digital）</td><td>QR码/二维码（序列化）</td><td>智能手机扫码</td><td>★★（码本身易复制）</td><td>¥0.01-0.1/件</td><td>消费品（需配合后端核验）</td></tr><tr><td>数字 （Digital）</td><td>NFC芯片</td><td>NFC手机感应</td><td>★★★★（芯片难以克隆）</td><td>¥1-5/件</td><td>奢侈品、高端电子</td></tr><tr><td>数字 （Digital）</td><td>区块链溯源</td><td>扫码查询区块链记录</td><td>★★★★★（数据不可篡改）</td><td>系统搭建成本高；查询近零成本</td><td>食品、药品、奢侈品、汽配</td></tr><tr><td>数字 （Digital）</td><td>DNA标记</td><td>专用DNA检测设备</td><td>★★★★★（生物特性）</td><td>¥5-20/件</td><td>极高价值产品；航材</td></tr></tbody></table><h2 id="_4-2-数字防伪与追溯体系构建" tabindex="-1">4.2　数字防伪与追溯体系构建 <a class="header-anchor" href="#_4-2-数字防伪与追溯体系构建" aria-label="Permalink to &quot;4.2　数字防伪与追溯体系构建&quot;">​</a></h2><h2 id="_4-2-1-序列化-serialization-是数字防伪的基础" tabindex="-1">4.2.1　序列化（Serialization）是数字防伪的基础 <a class="header-anchor" href="#_4-2-1-序列化-serialization-是数字防伪的基础" aria-label="Permalink to &quot;4.2.1　序列化（Serialization）是数字防伪的基础&quot;">​</a></h2><p>序列化是指为每件产品或每个包装单元赋予唯一的序列号（Serial Number），使其在供应链全程可被识别和追踪。序列化本身不能防止假冒，但它是所有数字验证技术的基础——没有序列化，就无法判断一个二维码是否被复制或重复使用。</p><ul><li>序列号生成：应由品牌持有人（或其授权的第三方平台）集中生成，禁止供应商自行生成序列号</li><li>序列号赋予：在生产环节（包装线末端）由品牌持有人监控下完成，而非交由供应商自行贴标</li><li>序列号激活：产品出厂时激活序列号记录（与发货单关联）；经销商签收时确认；消费者扫码时触发终端验证</li><li>异常检测：同一序列号在短时间内被多地（&gt;1个）扫描，触发系统预警（可能意味着该序列号被大量复制）</li></ul><h2 id="_4-2-2-区块链溯源的应用边界" tabindex="-1">4.2.2　区块链溯源的应用边界 <a class="header-anchor" href="#_4-2-2-区块链溯源的应用边界" aria-label="Permalink to &quot;4.2.2　区块链溯源的应用边界&quot;">​</a></h2><p>区块链为供应链溯源提供了不可篡改的数据基础，但其有效性高度依赖于「上链数据的真实性」——区块链能保证数据上链后不被篡改，但无法保证初始上链的数据本身是真实的（「垃圾进，垃圾出」问题）。 <em>区块链溯源的适用场景：产品涉及多个独立主体（农场→加工→流通→零售）、各方缺乏互信、需要向消费者/监管机构提供可验证的溯源信息。单一供应商链条中，传统ERP系统通常已足够。</em></p><ul><li>已有成熟应用：IBM Food Trust（食品安全）；Everledger（钻石/奢侈品）；MineTrace（矿产）；SGS/DNV的区块链认证服务</li><li>关键设计要素：链下数据锚定（物理防伪与链上数据绑定）；多方治理（避免单一主体控制链）；消费者查询端简洁易用</li></ul><h2 id="_4-3-防伪技术的供应链部署与管控" tabindex="-1">4.3　防伪技术的供应链部署与管控 <a class="header-anchor" href="#_4-3-防伪技术的供应链部署与管控" aria-label="Permalink to &quot;4.3　防伪技术的供应链部署与管控&quot;">​</a></h2><table tabindex="0"><thead><tr><th>部署环节</th><th>关键控制点</th><th>失控后果</th></tr></thead><tbody><tr><td>防伪材料采购</td><td>防伪标签/墨水/芯片供应商须经品牌持有人审核批准；禁止供应商自行采购同类材料</td><td>供应商可能通过同渠道采购额外防伪材料用于假冒品</td></tr><tr><td>防伪材料库存管理</td><td>防伪标签应在品牌持有人监督下按订单量领用，领用记录留存；废标须在监督下销毁</td><td>多余标签流入黑市，直接用于假冒品（带真实防伪标签的假冒品）</td></tr><tr><td>贴标/赋码环节</td><td>最好在品牌持有人自有设施或派驻监督员的条件下完成；至少应有CCTV覆盖和记录</td><td>未监控的贴标环节是超产假冒品「合法化」的最后一道门</td></tr><tr><td>序列号管理系统</td><td>序列号数据库由品牌持有人或其授权的中立第三方平台管理；供应商只有查询权，无修改权</td><td>供应商篡改序列号记录，掩盖超产或伪造出货记录</td></tr><tr><td>物流与仓储</td><td>防伪材料在运输中须全程封存；接收时对照数量核验；异常立即上报</td><td>运输途中截留防伪材料</td></tr></tbody></table><h1 id="第五章-海关执法与跨境知识产权保护" tabindex="-1">第五章　海关执法与跨境知识产权保护 <a class="header-anchor" href="#第五章-海关执法与跨境知识产权保护" aria-label="Permalink to &quot;第五章　海关执法与跨境知识产权保护&quot;">​</a></h1><h2 id="_5-1-海关备案-主动保护的第一步" tabindex="-1">5.1　海关备案：主动保护的第一步 <a class="header-anchor" href="#_5-1-海关备案-主动保护的第一步" aria-label="Permalink to &quot;5.1　海关备案：主动保护的第一步&quot;">​</a></h2><p>海关知识产权保护（Customs IP Recordal / Border Measures）是全球大多数司法管辖区均提供的主动保护工具。权利人向海关完成备案后，海关可依职权或依申请扣押疑似侵权货物，赋予权利人「在口岸拦截假冒品」的权利，而无需等到货物进入市场后才能通过法院起诉。</p><h2 id="_5-1-1-主要司法管辖区备案流程" tabindex="-1">5.1.1　主要司法管辖区备案流程 <a class="header-anchor" href="#_5-1-1-主要司法管辖区备案流程" aria-label="Permalink to &quot;5.1.1　主要司法管辖区备案流程&quot;">​</a></h2><table tabindex="0"><thead><tr><th>司法管辖区</th><th>备案机构</th><th>有效期</th><th>主要要求</th><th>关键优势</th></tr></thead><tbody><tr><td>中国</td><td>海关总署 （GACC）</td><td>10年 （可续展）</td><td>提供商标/版权/专利注册证书；品牌说明；正品样品或图片</td><td>全球规模最大的IP海关保护体系；2023年查获侵权货物超7,800万件</td></tr><tr><td>欧盟</td><td>任一成员国海关 （覆盖全EU）</td><td>1年 （可续展）</td><td>EU商标/版权权利证明；授权代理人在欧盟境内</td><td>一次申请覆盖27国；可申请「过境扣押」（in-transit seizure）</td></tr><tr><td>美国</td><td>CBP（海关与边境保护局）</td><td>20年 （与商标有效期一致）</td><td>USPTO注册商标；版权注册</td><td>CBP有权主动扣押；IPRB（知识产权权利中心）专项处理</td></tr><tr><td>英国</td><td>HMRC/边境部队</td><td>2年 （可续展）</td><td>UK商标/版权权利证明</td><td>脱欧后与EU体系独立；需单独申请</td></tr><tr><td>东南亚重点国家</td><td>各国海关 （越南/泰国/印尼）</td><td>各异 （1-3年）</td><td>当地注册商标/版权</td><td>需当地律师协助；部分国家主动执法能力有限</td></tr></tbody></table><h2 id="_5-1-2-过境扣押-in-transit-seizure-对中国出口商的特殊影响" tabindex="-1">5.1.2　过境扣押（In-Transit Seizure）：对中国出口商的特殊影响 <a class="header-anchor" href="#_5-1-2-过境扣押-in-transit-seizure-对中国出口商的特殊影响" aria-label="Permalink to &quot;5.1.2　过境扣押（In-Transit Seizure）：对中国出口商的特殊影响&quot;">​</a></h2><p>欧盟和部分其他司法管辖区允许对「过境货物」实施扣押，即便该货物的最终目的地并非该司法管辖区。这一机制对中国出口企业影响显著：</p><ul><li>风险情形：中国出口商将货物从深圳发往巴拿马，途经荷兰鹿特丹港中转。欧盟权利人在GACC备案了欧盟商标，即便货物目的地不是欧盟，荷兰海关仍可在中转期间扣押</li><li>2011年TRIPS修订后续争议：TRIPS第41-61条规定的边境措施主要针对进口，但欧盟的过境扣押实践超出了TRIPS最低义务。中国与欧盟在WTO争端解决机制下就此存在历史分歧（DS362）</li><li>应对策略：出口前完成目的地国海关备案（证明自身为权利人）；与货运代理确认中转港IP风险；高价值货物选择直达航线或规避争议中转港</li></ul><h2 id="_5-2-海关调查配合机制" tabindex="-1">5.2　海关调查配合机制 <a class="header-anchor" href="#_5-2-海关调查配合机制" aria-label="Permalink to &quot;5.2　海关调查配合机制&quot;">​</a></h2><p>当海关扣押疑似侵权货物时，权利人通常有短暂的时间窗口（在中国为3个工作日，欧盟一般10个工作日）提供真品鉴定意见。企业应建立应急鉴定响应机制：</p><ul><li>建立鉴定快速响应团队：指定IP部门/法务部门的海关联络人，确保24小时内可响应海关鉴定请求</li><li>准备鉴定材料包：预先准备好正品样品、产品图片对比说明、商标注册证书复印件，可快速邮件发送给海关</li><li>与海关建立日常联络：在贸易量大的口岸（深圳、上海、宁波、广州），考虑与当地海关IP保护部门建立定期沟通机制</li><li>跨国协调：对于跨境侵权（如中国制造→欧盟进口），协调中国律师/代理与目的地国律师同步行动</li></ul><h2 id="_5-3-特殊贸易形态的ip风险" tabindex="-1">5.3　特殊贸易形态的IP风险 <a class="header-anchor" href="#_5-3-特殊贸易形态的ip风险" aria-label="Permalink to &quot;5.3　特殊贸易形态的IP风险&quot;">​</a></h2><table tabindex="0"><thead><tr><th>贸易形态</th><th>IP风险特点</th><th>监控重点</th></tr></thead><tbody><tr><td>跨境电商 （B2C小包）</td><td>单件货值低、包裹量巨大，海关全面查验不现实；假冒品借助「个人自用」免税门槛规避</td><td>主要依赖平台治理；海关对高风险发件人建立特别检查机制；消费者举报</td></tr><tr><td>自贸区/保税区</td><td>货物在自贸区内不受常规IP检查；部分假冒品在区内完成换标</td><td>针对自贸区的专项IP检查；注意「洗产地」操作</td></tr><tr><td>展览/样品寄送</td><td>以「样品」名义进口的货物通常豁免常规商业检查；被用于假冒品小批量测试</td><td>展会前向目标展会所在地海关提交IP保护申请；现场鉴定人员部署</td></tr><tr><td>退货品回流</td><td>消费者退货经非官方渠道回流后再销售（尤其是奢侈品、电子消费品）</td><td>序列号追踪；退货品必须回到品牌持有人授权的处理渠道</td></tr></tbody></table><h1 id="第六章-线上渠道监控与电商平台治理" tabindex="-1">第六章　线上渠道监控与电商平台治理 <a class="header-anchor" href="#第六章-线上渠道监控与电商平台治理" aria-label="Permalink to &quot;第六章　线上渠道监控与电商平台治理&quot;">​</a></h1><h2 id="_6-1-平台责任框架的演变" tabindex="-1">6.1　平台责任框架的演变 <a class="header-anchor" href="#_6-1-平台责任框架的演变" aria-label="Permalink to &quot;6.1　平台责任框架的演变&quot;">​</a></h2><p>电商平台的IP责任框架在全球范围内持续演进，从「避风港原则」（通知-删除）向「主动预防义务」转变。这一趋势对品牌持有人既是压力也是机遇：平台被迫投入更多资源打假，但也要求品牌持有人在平台上完成品牌备案并主动参与维权。</p><table tabindex="0"><thead><tr><th>司法管辖区/平台</th><th>现行机制</th><th>品牌持有人义务</th><th>最新动态</th></tr></thead><tbody><tr><td>中国 淘宝/天猫/京东</td><td>阿里IPP（知识产权平台）；京东品牌保护系统；投诉删除+店铺处罚机制</td><td>完成平台品牌入驻；上传商标/版权证书；主动投诉侵权链接</td><td>阿里打假合作联盟（AACA）：汽配、医疗器械、食品品牌优先参与；2023年处置疑似侵权链接超1.4亿条</td></tr><tr><td>欧盟</td><td>数字服务法（DSA，2023年8月）：超大型平台须建立内部投诉机制；可信举报人（Trusted Flaggers）制度</td><td>注册为可信举报人可加速删除处理；提供结构化侵权通知</td><td>DSA要求VLOP定期发布透明度报告；可信举报人认定程序正在建立</td></tr><tr><td>美国 Amazon</td><td>Brand Registry（品牌注册）；Project Zero（品牌持有人直接删除权）；Counterfeit Crimes Unit</td><td>完成Brand Registry注册（需USPTO注册号）；使用A+自动防护</td><td>2023年Amazon起诉超5,000个卖假账户；与DHS共享侵权信息</td></tr><tr><td>跨境电商 Shopee/Lazada</td><td>各平台IP投诉通道；Shopee IP Protection Tool；Lazada IP Hub</td><td>上传当地注册证书；按平台格式提交投诉</td><td>东南亚假冒品增速快；平台治理能力相对EU/美国仍有差距</td></tr></tbody></table><h2 id="_6-2-品牌监控sop-从发现到处置" tabindex="-1">6.2　品牌监控SOP：从发现到处置 <a class="header-anchor" href="#_6-2-品牌监控sop-从发现到处置" aria-label="Permalink to &quot;6.2　品牌监控SOP：从发现到处置&quot;">​</a></h2><h2 id="_6-2-1-线上假冒品处置流程" tabindex="-1">6.2.1　线上假冒品处置流程 <a class="header-anchor" href="#_6-2-1-线上假冒品处置流程" aria-label="Permalink to &quot;6.2.1　线上假冒品处置流程&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>动作</th><th>时限</th><th>负责方</th></tr></thead><tbody><tr><td>1. 发现</td><td>监控工具触发预警；人工确认侵权链接；截图存证（包含URL、店铺名称、商品图片、价格、销量）</td><td>T+0（预警当天）</td><td>品牌保护团队/第三方监控服务</td></tr><tr><td>2. 评估优先级</td><td>根据：商品类别（安全风险优先）、销售量、侵权程度（高仿vs轻度混淆）、卖家历史记录，确定处置优先级</td><td>T+1（24小时内）</td><td>IP/法务部门</td></tr><tr><td>3. 证据固定</td><td>公证存证（关键大案）；网页快照工具（Wayback Machine等）；购买取证样品（买样）</td><td>T+1至T+3</td><td>IP/法务部门＋外部律师</td></tr><tr><td>4. 平台投诉</td><td>通过平台IP投诉工具提交：侵权证据+商标注册证书+声明；追踪处理进度</td><td>T+2（高优先级） T+5（一般）</td><td>品牌保护团队</td></tr><tr><td>5. 行政举报</td><td>向市场监管部门（AMR）、公安网安支队举报重大线索；海关备案拦截货源</td><td>视情况：发现货源地时同步进行</td><td>法务部门＋外部律师</td></tr><tr><td>6. 司法维权</td><td>民事诉讼（损害赔偿）；刑事控告（规模化假冒）；财产保全（冻结侵权方账户）</td><td>重大案件：T+5至T+30</td><td>外部律师</td></tr><tr><td>7. 数据归档</td><td>将所有侵权案例录入IP维权数据库：侵权主体、处置结果、赔偿金额、惯犯追踪</td><td>每月归档</td><td>IP部门</td></tr></tbody></table><h2 id="_6-3-内容权利管理-digital-rights-management" tabindex="-1">6.3　内容权利管理（Digital Rights Management） <a class="header-anchor" href="#_6-3-内容权利管理-digital-rights-management" aria-label="Permalink to &quot;6.3　内容权利管理（Digital Rights Management）&quot;">​</a></h2><p>除商标侵权外，品牌在线上还面临版权内容被盗用的问题：产品图片被他人用于假冒品销售页面；品牌宣传视频被剪辑后用于诈骗广告；官方教程内容被字面复制到竞品页面。</p><ul><li>图片保护：在官方产品图片中嵌入隐形水印（Stegano-based watermarking）；通过图像识别AI（Google Vision、TinEye、二郎神等国内工具）监控盗用图片</li><li>DMCA/《著作权法》通知：向使用侵权图片/视频的平台发送版权侵权通知（DMCA Takedown for US/UK platforms；《信息网络传播权保护条例》通知for中国平台）</li><li>域名盗用：注册关键品牌词的.com/.cn/.eu域名；对typosquatting域名（差一个字母）提起UDRP或CDRP仲裁（比诉讼更快、更低成本）</li></ul><h1 id="第七章-供应商知识产权合规评估体系" tabindex="-1">第七章　供应商知识产权合规评估体系 <a class="header-anchor" href="#第七章-供应商知识产权合规评估体系" aria-label="Permalink to &quot;第七章　供应商知识产权合规评估体系&quot;">​</a></h1><h2 id="_7-1-供应商ip风险分层框架" tabindex="-1">7.1　供应商IP风险分层框架 <a class="header-anchor" href="#_7-1-供应商ip风险分层框架" aria-label="Permalink to &quot;7.1　供应商IP风险分层框架&quot;">​</a></h2><p>并非所有供应商都需要同等强度的IP合规管理。IP合规管理资源应按风险集中部署。以下分层框架帮助采购和法务团队确定哪些供应商需要最严格的IP管控：</p><table tabindex="0"><thead><tr><th>层级</th><th>供应商类型</th><th>IP风险特征</th><th>管控要求</th></tr></thead><tbody><tr><td>第一层 （关键风险）</td><td>接触核心IP资产的OEM/ODM/CM供应商；掌握配方/工艺的T1供应商；代工厂（使用品牌商模具/标签）</td><td>直接接触商业秘密；持有品牌商标使用权；可能超产假冒；模具管控风险</td><td>完整IP条款合同；商标授权协议；年度审核；产量审计；防伪材料管控；NDA+竞业限制</td></tr><tr><td>第二层 （中等风险）</td><td>T2关键原料/关键零部件供应商；持有品牌商产品设计信息的工具商/模具商</td><td>接触技术文件；产品规格外泄风险；供应给多个竞争客户</td><td>NDA；技术文件分级管理；基础IP条款；每2年审核</td></tr><tr><td>第三层 （基础风险）</td><td>标准化原材料/通用件供应商；物流/仓储服务商（接触成品但非设计）</td><td>成品包装识别风险；品牌信息在运输中暴露</td><td>标准采购条款含IP保护条款；关注异常行为举报机制</td></tr><tr><td>第四层 （低风险）</td><td>办公耗材/非核心服务供应商</td><td>极少接触IP资产</td><td>标准保密条款即可</td></tr></tbody></table><h2 id="_7-2-ip合规问卷-供应商自评" tabindex="-1">7.2　IP合规问卷（供应商自评） <a class="header-anchor" href="#_7-2-ip合规问卷-供应商自评" aria-label="Permalink to &quot;7.2　IP合规问卷（供应商自评）&quot;">​</a></h2><p>以下问卷适用于第一层和第二层供应商的年度自评，也可作为新供应商准入评估工具。问卷分为五个维度，总分100分。</p><h2 id="_7-2-1-问卷设计框架" tabindex="-1">7.2.1　问卷设计框架 <a class="header-anchor" href="#_7-2-1-问卷设计框架" aria-label="Permalink to &quot;7.2.1　问卷设计框架&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>核心问题</th><th>满分</th><th>评分依据</th></tr></thead><tbody><tr><td>IP基础设施 （20分）</td><td>贵公司是否持有与所经营业务相关的IP权利（商标/专利/版权/商业秘密）？是否已在主要市场完成注册？是否设立专职IP管理人员或外聘IP代理？</td><td>20</td><td>IP台账清单；注册证书；IP管理制度文件</td></tr><tr><td>技术文件保护 （20分）</td><td>贵公司是否建立技术文件保密管理制度（含分级标准）？是否与员工签订保密协议和竞业限制协议？是否控制分包商对技术文件的访问？</td><td>20</td><td>保密制度文件；NDA模板；分包商管理流程</td></tr><tr><td>商标及品牌保护 （20分）</td><td>贵公司是否建立防止未经授权贴标/使用商标的内部程序？是否有产量报告机制供客户核验？模具是否为客户品牌专用并有库存管控？</td><td>20</td><td>贴标操作规程；产量报告；模具台账</td></tr><tr><td>反仿冒措施 （20分）</td><td>贵公司的产品/包装是否采用防伪技术？是否建立原材料来源核查机制防止假冒原材料进入生产？是否有仿冒品举报渠道？</td><td>20</td><td>防伪技术说明；供应商审核记录；举报机制介绍</td></tr><tr><td>执法与救济 （20分）</td><td>贵公司过去3年是否有IP侵权被指控或主动维权的记录？是否与主要客户签订含IP保护条款的供应商协议？是否有内部IP合规培训？</td><td>20</td><td>侵权/维权记录（如有）；协议文本；培训记录</td></tr></tbody></table><h2 id="_7-3-供应商现场ip审核指引" tabindex="-1">7.3　供应商现场IP审核指引 <a class="header-anchor" href="#_7-3-供应商现场ip审核指引" aria-label="Permalink to &quot;7.3　供应商现场IP审核指引&quot;">​</a></h2><p>供应商自评问卷仅是第一步。对于第一层供应商，建议每年开展一次现场IP审核，重点检查以下领域：</p><h2 id="_7-3-1-现场审核重点检查项" tabindex="-1">7.3.1　现场审核重点检查项 <a class="header-anchor" href="#_7-3-1-现场审核重点检查项" aria-label="Permalink to &quot;7.3.1　现场审核重点检查项&quot;">​</a></h2><table tabindex="0"><thead><tr><th>审核领域</th><th>检查项目</th><th>主要证据来源</th><th>高风险信号</th></tr></thead><tbody><tr><td>模具与工装管控</td><td>品牌专属模具是否有独立台账；是否与通用模具物理隔离；废旧模具销毁记录</td><td>模具台账；库存盘点；销毁证明</td><td>模具台账数量与客户订单不符；废旧模具去向不明</td></tr><tr><td>防伪材料库存</td><td>防伪标签/芯片数量是否与出货量一致；废标销毁流程；标签领用记录</td><td>标签领用单；出货单交叉核对；废标记录</td><td>标签余量显著超出正常损耗；领用人无法说明标签去向</td></tr><tr><td>技术文件访问控制</td><td>技术文件服务器/系统的访问权限设置；离职员工账户注销记录；打印记录</td><td>IT系统访问日志；离职流程记录</td><td>离职员工账户仍处于活跃状态；无打印权限管控</td></tr><tr><td>分包商管控</td><td>是否有未披露的分包商；分包商是否接触技术文件；分包合同是否含保密条款</td><td>供应商名录；合同文本；现场访问控制</td><td>发现未知分包商；生产设施有不明第三方人员</td></tr><tr><td>产量核对</td><td>与近6个月订单对应的原材料采购量；半成品/成品库存；出货记录</td><td>采购发票；仓库库存记录；发货清单</td><td>成品数量显著超出客户订单；原材料采购量不合理</td></tr><tr><td>NDA执行情况</td><td>关键岗位员工签署的NDA记录；IP培训出勤记录；离职流程是否包含IP事项确认</td><td>NDA签署名单；培训签到表；离职面谈记录</td><td>核心技术岗位员工未签NDA；无IP相关培训记录</td></tr></tbody></table><h1 id="第八章-供应链ip合同保护机制" tabindex="-1">第八章　供应链IP合同保护机制 <a class="header-anchor" href="#第八章-供应链ip合同保护机制" aria-label="Permalink to &quot;第八章　供应链IP合同保护机制&quot;">​</a></h1><h2 id="_8-1-合同保护的整体架构" tabindex="-1">8.1　合同保护的整体架构 <a class="header-anchor" href="#_8-1-合同保护的整体架构" aria-label="Permalink to &quot;8.1　合同保护的整体架构&quot;">​</a></h2><p>供应链IP保护的合同体系通常由三个层次构成：（1）采购框架协议（MSA/MPSA）中的IP章节；（2）单独签署的保密协议（NDA）；（3）特定产品类别的知识产权授权协议（TLA/IP License）。三个层次的功能互补，不应简单合并为一份协议。</p><h2 id="_8-1-1-采购框架协议中的ip核心条款" tabindex="-1">8.1.1　采购框架协议中的IP核心条款 <a class="header-anchor" href="#_8-1-1-采购框架协议中的ip核心条款" aria-label="Permalink to &quot;8.1.1　采购框架协议中的IP核心条款&quot;">​</a></h2><table tabindex="0"><thead><tr><th>条款类型</th><th>核心内容</th><th>重要性说明</th></tr></thead><tbody><tr><td>IP所有权条款</td><td>供应商在执行采购订单过程中产生的一切发明、改进、工作成果（含定制设计、改良工艺），其知识产权归属于采购方（或双方协商的比例）</td><td>★★★★★ 防止供应商以「承包方」身份主张对定制开发内容的IP权利；尤其重要于OEM/ODM模式</td></tr><tr><td>背景IP与前景IP划分</td><td>明确界定双方在合作前已有的IP（背景IP）和合作中产生的IP（前景IP）；背景IP各自保留，前景IP归属按约定</td><td>★★★★ 避免「背景IP许可」陷阱——供应商可能主张其背景IP对采购方定制产品的使用权</td></tr><tr><td>保密义务</td><td>供应商在合同存续期间及终止后[N]年内对采购方披露的信息负有保密义务；第N+1年起对已进入公共领域的信息除外</td><td>★★★★★ 持续保密义务是商业秘密保护的合同基础</td></tr><tr><td>禁止转让禁止再许可</td><td>供应商不得将合同项下的IP授权转让或再许可给任何第三方（含关联公司）</td><td>★★★★ 防止供应商通过分拆关联公司绕过IP保护</td></tr><tr><td>审计权</td><td>采购方有权（预约或突击）审计供应商的生产记录、IP资产台账和保密措施落实情况</td><td>★★★★ 合同审计权是现场IP审核的法律基础；无此条款则现场检查无合同依据</td></tr><tr><td>违约赔偿</td><td>IP相关违约适用惩罚性赔偿条款；赔偿金额不低于[X]倍的采购合同金额或实际损失的[Y]倍（两者取高）</td><td>★★★★★ IP条款的威慑力很大程度取决于违约成本设定</td></tr><tr><td>管辖法律与争议解决</td><td>建议选择采购方所在地法律；仲裁优于诉讼（尤其跨境场景）；CIETAC/ICC/HKIAC可根据交易规模选择</td><td>★★★★ 跨国供应链中管辖权条款至关重要</td></tr></tbody></table><h2 id="_8-2-知识产权归属的常见陷阱" tabindex="-1">8.2　知识产权归属的常见陷阱 <a class="header-anchor" href="#_8-2-知识产权归属的常见陷阱" aria-label="Permalink to &quot;8.2　知识产权归属的常见陷阱&quot;">​</a></h2><p>知识产权归属条款是供应链合同中争议最多的领域。以下是采购方需要防范的常见陷阱：</p><table tabindex="0"><thead><tr><th>陷阱类型</th><th>典型场景</th><th>风险后果</th><th>防范措施</th></tr></thead><tbody><tr><td>职务发明争议</td><td>供应商员工在执行定制订单中产生改进方案，供应商主张该改进属于员工的职务发明，IP归属于供应商</td><td>采购方花费研发成本支持的改进被供应商申请专利，转而向采购方主张专利使用费</td><td>合同明确：定制开发成果（含改进）的IP权利归采购方；供应商须确保其员工的相关发明已依法向供应商让渡，再转让给采购方</td></tr><tr><td>联合发明风险</td><td>采购方工程师与供应商工程师共同解决生产问题，产生可专利的新方案</td><td>双方均可主张联合发明权；若供应商先行申请专利，采购方需许可才能使用</td><td>合同中设定：涉及采购方参与的共同技术开发，须书面确认各方贡献和IP归属；及时申请联合专利或约定一方代为申请并授权另一方使用</td></tr><tr><td>外观设计规避</td><td>供应商持有「仿似」设计（与品牌外观设计近似但稍有区别），据此向品牌持有人索赔或干扰商标注册</td><td>品牌持有人被迫应诉或支付和解费用</td><td>提前在主要制造国注册外观设计专利；合同中明确：供应商不得申请与采购方产品外观相似的知识产权</td></tr><tr><td>商业秘密被内化</td><td>供应商通过多年合作获得采购方的核心工艺信息，合同终止后将其作为自身「技术积累」继续使用</td><td>无合同约束时难以证明侵权；举证成本极高</td><td>在NDA中明确列举受保护的核心信息类别；合同终止时进行IP资产清点和销毁确认；必要时在合同中约定竞争禁止期</td></tr></tbody></table><details class="details custom-block"><summary>延伸阅读：真实案例——Waymo诉Uber自动驾驶技术窃密案</summary><p><strong>Waymo（谷歌）诉Uber商业秘密案（2017–2018年）</strong>：谷歌自动驾驶项目（后独立为Waymo）以联邦商业秘密法（DTSA）对Uber及其收购的自动驾驶公司Otto提起诉讼。核心指控：Waymo前工程师安东尼·莱万多斯基（Anthony Levandowski）在离职前下载了约14,000份包含激光雷达（LiDAR）核心技术的机密文件，随后创立Otto，Otto被Uber以6.8亿美元收购。</p><p>2018年，双方达成和解：Uber向Waymo支付价值约2.45亿美元的Uber股权，并承诺不在其技术产品中使用Waymo的商业秘密。莱万多斯基本人则于2020年在联邦法院被判处18个月监禁（后获总统特赦）。</p><p><strong>案件对供应链IP管理的启示：</strong></p><ul><li><strong>离职前的文件下载行为是最高风险节点</strong>：14,000份文件的下载发生在莱万多斯基提出辞职前的数周内。此类行为模式（即将离职的核心人员短时间内大量访问/下载核心技术文件）<strong>应在DLP系统和访问日志中设置自动告警规则</strong>。</li><li><strong>收购目标的IP来源须做专项尽职调查（IP Due Diligence）</strong>：Uber在收购Otto时未能（或未愿意）充分调查Otto核心技术的来源合法性，最终付出了高额代价。在供应链场景中，若采购方收购供应商或其关键技术团队，须对技术资产来源进行严格审查。</li><li><strong>&quot;我拥有这段代码/工艺，所以可以带走&quot;是错误认知</strong>：职务发明和工作成果的IP归属于雇主；即便员工是核心贡献者，离职时也无权带走任何形式的工作成果（含记忆中的核心算法细节，视司法管辖区而定）。</li></ul></details><h2 id="_8-3-odm模式的特殊ip风险" tabindex="-1">8.3　ODM模式的特殊IP风险 <a class="header-anchor" href="#_8-3-odm模式的特殊ip风险" aria-label="Permalink to &quot;8.3　ODM模式的特殊IP风险&quot;">​</a></h2><p>原始设计制造商（ODM）模式下，供应商不仅制造，还提供设计能力。这一模式给品牌持有人带来额外的IP风险，需要特殊的合同安排：</p><ul><li>设计平台IP：ODM供应商通常基于其通用设计平台进行定制，品牌商仅获得平台的「使用权」而非「所有权」。一旦合作终止，品牌商无法带走底层设计</li><li>同款多牌：ODM供应商可能向多个品牌商提供基于相同平台的定制产品，导致品牌商的「独家定制」产品实为同款多标</li><li>防范措施：在合同中明确区分「通用平台」（供应商保留IP）和「品牌定制层」（采购方IP）；约定独家定制条款或最短独家期；约定供应商在生产本品牌产品期间不得向竞争品牌供货同款</li></ul><h1 id="第九章-ip合规审核方法论与评分框架" tabindex="-1">第九章　IP合规审核方法论与评分框架 <a class="header-anchor" href="#第九章-ip合规审核方法论与评分框架" aria-label="Permalink to &quot;第九章　IP合规审核方法论与评分框架&quot;">​</a></h1><h2 id="_9-1-审核全天流程安排" tabindex="-1">9.1　审核全天流程安排 <a class="header-anchor" href="#_9-1-审核全天流程安排" aria-label="Permalink to &quot;9.1　审核全天流程安排&quot;">​</a></h2><p>针对第一层供应商的标准IP审核建议以一整天为单位。以下为推荐的审核日程安排：</p><table tabindex="0"><thead><tr><th>时段</th><th>内容</th><th>审核方式</th><th>输出</th></tr></thead><tbody><tr><td>08:30-09:00</td><td>开场说明与文件请求清单确认</td><td>会议室 开场会议</td><td>文件请求清单（DRL）确认</td></tr><tr><td>09:00-10:30</td><td>IP制度体系文件审查 — IP管理制度 — NDA模板 — IP培训材料 — 保密等级分类制度</td><td>文件审查</td><td>制度文件得分（满分20分）</td></tr><tr><td>10:30-12:00</td><td>技术文件访问控制核查 — IT系统访问权限演示 — 离职员工账户状态 — 文件服务器权限截图 — 打印/下载记录</td><td>IT系统演示 +文件审查</td><td>技术保护措施得分（满分25分）</td></tr><tr><td>12:00-13:00</td><td>午休</td><td>—</td><td>—</td></tr><tr><td>13:00-14:30</td><td>生产区域现场检查 — 模具台账核对 — 防伪标签库存核对 — 贴标工序CCTV记录 — 分包商情况核查</td><td>现场巡查 +台账交叉核对</td><td>生产管控得分（满分25分）</td></tr><tr><td>14:30-15:30</td><td>人员访谈 — IP负责人（制度层面） — 生产主管（操作层面） — 离职管理HR（人员管控）</td><td>一对一 访谈</td><td>人员与文化得分（满分15分）</td></tr><tr><td>15:30-16:30</td><td>记录与整合 — 汇总各维度评分 — 起草整改建议初稿 — 确认关键发现</td><td>内部讨论</td><td>审核初步评分</td></tr><tr><td>16:30-17:00</td><td>闭幕会议 — 反馈主要发现 — 确认整改时间表 — 签署审核记录</td><td>会议室 闭幕会议</td><td>签署的审核记录 整改计划初稿</td></tr></tbody></table><h2 id="_9-2-ip合规综合评分矩阵-满分100分" tabindex="-1">9.2　IP合规综合评分矩阵（满分100分） <a class="header-anchor" href="#_9-2-ip合规综合评分矩阵-满分100分" aria-label="Permalink to &quot;9.2　IP合规综合评分矩阵（满分100分）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>评估维度</th><th>子项</th><th>满分</th><th>评分标准（参考）</th></tr></thead><tbody><tr><td>1. IP制度体系 （20分）</td><td>IP管理制度完备性</td><td>8</td><td>无制度=0；制度存在但不完整=4；完整且定期更新=8</td></tr><tr><td>1. IP制度体系 （20分）</td><td>NDA覆盖率（员工+供应商）</td><td>7</td><td>覆盖率&lt;50%=0；50-90%=4；&gt;90%=7</td></tr><tr><td>1. IP制度体系 （20分）</td><td>IP培训（频率+覆盖岗位）</td><td>5</td><td>无培训=0；年度培训但覆盖不全=3；全员年度培训=5</td></tr><tr><td>2. 技术文件保护 （25分）</td><td>文件分级与访问控制</td><td>10</td><td>无分级=0；有分级但执行不严=5；严格分级+系统控制=10</td></tr><tr><td>2. 技术文件保护 （25分）</td><td>离职管理（账户注销+IP确认）</td><td>8</td><td>无流程=0；有流程但执行滞后=4；完善流程+证据留存=8</td></tr><tr><td>2. 技术文件保护 （25分）</td><td>分包商管控</td><td>7</td><td>无管控=0；有合同约束=4；合同+访问控制+审计=7</td></tr><tr><td>3. 生产区管控 （25分）</td><td>模具台账与物理管控</td><td>10</td><td>无台账=0；台账不完整=5；完整台账+物理隔离=10</td></tr><tr><td>3. 生产区管控 （25分）</td><td>防伪材料库存管控</td><td>8</td><td>无管控=0；有台账但不对账=4；台账+定期对账+废标记录=8</td></tr><tr><td>3. 生产区管控 （25分）</td><td>贴标/赋码工序监控</td><td>7</td><td>无监控=0；CCTV覆盖=4；CCTV+记录留存+派驻监督=7</td></tr><tr><td>4. 人员与文化 （15分）</td><td>关键岗位NDA签署完整性</td><td>6</td><td>关键岗位覆盖&lt;80%=0；80-95%=3；&gt;95%=6</td></tr><tr><td>4. 人员与文化 （15分）</td><td>IP合规意识（访谈结果）</td><td>5</td><td>意识薄弱=0；基本了解=3；深入理解+实践=5</td></tr><tr><td>4. 人员与文化 （15分）</td><td>IP事件历史（过去3年）</td><td>4</td><td>有重大IP事件且未整改=0；有事件已整改=2；无重大事件=4</td></tr><tr><td>5. 执法与救济 （15分）</td><td>海关/平台IP备案完整性</td><td>5</td><td>无备案=0；部分备案=3；主要市场全部备案=5</td></tr><tr><td>5. 执法与救济 （15分）</td><td>监控体系（商标/电商/市场）</td><td>5</td><td>无监控=0；被动响应=2；主动监控+快速响应=5</td></tr><tr><td>5. 执法与救济 （15分）</td><td>维权记录与效果</td><td>5</td><td>无维权记录（高风险场景）=2；有维权案例且结果良好=5</td></tr></tbody></table><h2 id="_9-3-审核结果等级与整改路径" tabindex="-1">9.3　审核结果等级与整改路径 <a class="header-anchor" href="#_9-3-审核结果等级与整改路径" aria-label="Permalink to &quot;9.3　审核结果等级与整改路径&quot;">​</a></h2><p><em>图9-1　IP合规综合审核评分等级示意图（满分100分）</em></p><table tabindex="0"><thead><tr><th>综合得分</th><th>风险等级</th><th>含义</th><th>整改要求</th></tr></thead><tbody><tr><td>85-100</td><td>低风险（绿色）</td><td>IP合规体系完善，管控措施有效落实</td><td>年度例行审核；在可接受范围内维持合作</td></tr><tr><td>70-84</td><td>中等风险（黄色）</td><td>IP合规体系基本建立，存在若干执行缺口</td><td>90天内提交整改计划；6个月内复核整改进展</td></tr><tr><td>55-69</td><td>较高风险（橙色）</td><td>IP合规存在系统性缺口，特定方面管控薄弱</td><td>60天内整改计划；3个月内现场复核；暂停新增合同直至整改通过</td></tr><tr><td>40-54</td><td>高风险（红色）</td><td>IP合规严重不足，多个关键控制点缺失</td><td>30天内整改计划；暂停高敏感度订单；60天内现场复核；未整改则启动替代供应商</td></tr><tr><td>&lt;40</td><td>危险（黑色）</td><td>IP保护几近空白，存在主动侵权迹象</td><td>立即暂停全部订单；启动法律评估；退出前须完成IP资产清点（收回模具/技术文件/标签）</td></tr></tbody></table><h1 id="第十章-ip审核检查清单" tabindex="-1">第十章　IP审核检查清单 <a class="header-anchor" href="#第十章-ip审核检查清单" aria-label="Permalink to &quot;第十章　IP审核检查清单&quot;">​</a></h1><h2 id="_10-1-ip制度与文件检查清单" tabindex="-1">10.1　IP制度与文件检查清单 <a class="header-anchor" href="#_10-1-ip制度与文件检查清单" aria-label="Permalink to &quot;10.1　IP制度与文件检查清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>检查项目</th><th>检查方式</th><th>符合（Y/N/NA）</th><th>备注</th></tr></thead><tbody><tr><td>1</td><td>供应商是否持有IP管理制度并定期（至少每2年）更新</td><td>查阅文件</td><td></td><td></td></tr><tr><td>2</td><td>供应商是否有专职或兼职IP管理人员（明确职责）</td><td>人员访谈</td><td></td><td></td></tr><tr><td>3</td><td>供应商与全体研发/生产关键岗位员工是否签订NDA</td><td>名单对比+抽查签署记录</td><td></td><td></td></tr><tr><td>4</td><td>供应商与全体关键岗位员工是否签订竞业限制协议（含离职后禁止期）</td><td>名单对比+抽查协议</td><td></td><td></td></tr><tr><td>5</td><td>供应商是否建立技术文件保密分级制度（≥3级）</td><td>查阅制度文件</td><td></td><td></td></tr><tr><td>6</td><td>供应商是否有IP培训记录（过去12个月内）</td><td>培训签到表+材料</td><td></td><td></td></tr><tr><td>7</td><td>供应商的离职流程是否包含IP事项确认（账户注销+文件返还/销毁）</td><td>流程文件+近期离职案例</td><td></td><td></td></tr><tr><td>8</td><td>供应商是否有IP侵权举报渠道（内部举报机制）</td><td>制度文件+渠道验证</td><td></td><td></td></tr></tbody></table><h2 id="_10-2-商标与品牌保护检查清单" tabindex="-1">10.2　商标与品牌保护检查清单 <a class="header-anchor" href="#_10-2-商标与品牌保护检查清单" aria-label="Permalink to &quot;10.2　商标与品牌保护检查清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>检查项目</th><th>检查方式</th><th>符合（Y/N/NA）</th><th>备注</th></tr></thead><tbody><tr><td>9</td><td>供应商持有的客户商标使用授权是否有书面协议（含有效期、使用范围限制）</td><td>查阅授权协议</td><td></td><td></td></tr><tr><td>10</td><td>供应商的模具台账是否完整（客户专属模具单独列明）</td><td>台账核对+现场盘点</td><td></td><td></td></tr><tr><td>11</td><td>客户专属模具是否与通用模具物理隔离存放</td><td>现场核查</td><td></td><td></td></tr><tr><td>12</td><td>供应商是否有产量报告机制（定期向客户报告实际产量）</td><td>查阅报告记录</td><td></td><td></td></tr><tr><td>13</td><td>防伪标签/序列码的领用记录是否完整且与出货量匹配</td><td>台账交叉核对</td><td></td><td></td></tr><tr><td>14</td><td>废旧/损毁防伪材料是否有销毁记录（含监督人签字）</td><td>查阅销毁记录</td><td></td><td></td></tr><tr><td>15</td><td>贴标/赋码工序是否有CCTV覆盖并留存记录</td><td>现场查看+录像记录核查</td><td></td><td></td></tr><tr><td>16</td><td>供应商是否向其他客户提供与本品牌外观相似的产品</td><td>访谈+产品样品核查</td><td></td><td></td></tr></tbody></table><h2 id="_10-3-技术文件与数字安全检查清单" tabindex="-1">10.3　技术文件与数字安全检查清单 <a class="header-anchor" href="#_10-3-技术文件与数字安全检查清单" aria-label="Permalink to &quot;10.3　技术文件与数字安全检查清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>检查项目</th><th>检查方式</th><th>符合（Y/N/NA）</th><th>备注</th></tr></thead><tbody><tr><td>17</td><td>技术文件服务器/系统是否启用身份认证和权限控制</td><td>IT演示</td><td></td><td></td></tr><tr><td>18</td><td>核心技术文件（绝密/机密级）是否限制下载/打印/截图</td><td>IT演示+日志抽查</td><td></td><td></td></tr><tr><td>19</td><td>是否有访问日志（至少保留12个月）</td><td>IT日志查阅</td><td></td><td></td></tr><tr><td>20</td><td>所有离职员工（过去24个月）的系统账户是否已注销</td><td>IT账户列表核对</td><td></td><td></td></tr><tr><td>21</td><td>分包商/转包商是否仅能访问完成其工作所必需的技术文件（最小化披露）</td><td>分包商合同+访问记录</td><td></td><td></td></tr><tr><td>22</td><td>供应商是否对从事多客户业务的服务器进行逻辑隔离（不同客户数据隔离）</td><td>IT演示+访谈</td><td></td><td></td></tr><tr><td>23</td><td>技术文件传输是否使用加密通道（非明文邮件）</td><td>IT政策文件+演示</td><td></td><td></td></tr></tbody></table><h2 id="_10-4-海关备案与监控检查清单" tabindex="-1">10.4　海关备案与监控检查清单 <a class="header-anchor" href="#_10-4-海关备案与监控检查清单" aria-label="Permalink to &quot;10.4　海关备案与监控检查清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>检查项目</th><th>检查方式</th><th>符合（Y/N/NA）</th><th>备注</th></tr></thead><tbody><tr><td>24</td><td>品牌持有人是否已在主要生产国海关完成IP备案（商标/版权）</td><td>查阅备案证明</td><td></td><td></td></tr><tr><td>25</td><td>品牌持有人是否已在主要目的地国家/地区海关完成IP备案</td><td>查阅备案证明</td><td></td><td></td></tr><tr><td>26</td><td>海关备案是否在有效期内（无过期未续展情况）</td><td>查阅备案证书</td><td></td><td></td></tr><tr><td>27</td><td>品牌持有人是否建立了海关紧急响应机制（收到扣押通知后[X]小时内响应）</td><td>查阅SOP文件</td><td></td><td></td></tr><tr><td>28</td><td>是否建立了电商平台监控机制（主要平台品牌保护账号）</td><td>账号演示</td><td></td><td></td></tr><tr><td>29</td><td>过去12个月的平台投诉处理记录（处理数量、平均处理时间）</td><td>查阅记录</td><td></td><td></td></tr><tr><td>30</td><td>是否有商标注册监控（新申请近似商标的预警机制）</td><td>IP监控服务合同/工具演示</td><td></td><td></td></tr></tbody></table><h1 id="附录" tabindex="-1">附录 <a class="header-anchor" href="#附录" aria-label="Permalink to &quot;附录&quot;">​</a></h1><h2 id="附录a-ip红旗预警指标一览" tabindex="-1">附录A　IP红旗预警指标一览 <a class="header-anchor" href="#附录a-ip红旗预警指标一览" aria-label="Permalink to &quot;附录A　IP红旗预警指标一览&quot;">​</a></h2><p>以下任一情形出现，均应立即触发升级调查：</p><table tabindex="0"><thead><tr><th>类别</th><th>红旗信号</th><th>可能意味着</th></tr></thead><tbody><tr><td>产量异常</td><td>原材料采购量显著超出客户订单量（超出5%以上且无合理解释）</td><td>超产假冒品生产中</td></tr><tr><td>标签异常</td><td>防伪标签领用量超出出货量；废标记录缺失或不完整</td><td>多余标签可能流向黑市</td></tr><tr><td>模具异常</td><td>客户专属模具出现不明损耗、去向不明或被发现在非授权时段使用</td><td>模具被用于生产假冒品</td></tr><tr><td>人员异常</td><td>核心技术人员频繁离职；离职员工加入竞争对手或自行创业于相关领域</td><td>商业秘密可能随人员流失</td></tr><tr><td>市场信号</td><td>客户/经销商反映市场上出现与正品质量相似的低价同款；消费者投诉真品验证失败</td><td>超产假冒品已流入市场</td></tr><tr><td>数字信号</td><td>同一序列号在多个地点被扫描；QR码验证系统检测到异常高频扫描</td><td>序列号被批量复制</td></tr><tr><td>合同行为</td><td>供应商拒绝接受产量报告条款；拒绝模具所有权归属于客户；主动要求删除审计权条款</td><td>供应商存在违规意图</td></tr><tr><td>法律信号</td><td>发现供应商针对客户品牌提起商标/外观设计/专利异议或申请</td><td>供应商存在IP攻击意图</td></tr></tbody></table><h2 id="附录b-主要ip监控工具与平台资源" tabindex="-1">附录B　主要IP监控工具与平台资源 <a class="header-anchor" href="#附录b-主要ip监控工具与平台资源" aria-label="Permalink to &quot;附录B　主要IP监控工具与平台资源&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具/资源</th><th>类型</th><th>功能</th><th>适用场景</th></tr></thead><tbody><tr><td>Corsearch</td><td>商业工具（付费）</td><td>商标监控（新申请近似商标预警）；电商平台假冒品监控；域名监控</td><td>大中型品牌持有人的全球IP监控</td></tr><tr><td>MarkMonitor</td><td>商业工具（付费）</td><td>域名保护；网络假冒品监控；品牌滥用检测</td><td>奢侈品/科技品牌数字IP保护</td></tr><tr><td>Red Points</td><td>商业工具（付费）</td><td>AI驱动的电商平台假冒品自动检测和投诉提交</td><td>中小品牌电商平台假冒品管理</td></tr><tr><td>WIPO Global Brand Database</td><td>免费公共资源</td><td>全球商标注册查询；近似商标检索</td><td>商标注册监控基础工具</td></tr><tr><td>CNIPA商标网</td><td>免费公共资源</td><td>中国商标注册申请查询；近似商标检索；驳回/异议状态查询</td><td>中国市场商标保护必备工具</td></tr><tr><td>阿里知识产权平台（IPP）</td><td>平台工具（需备案）</td><td>阿里系平台（淘宝/天猫/速卖通）的侵权投诉；大数据溯源协助</td><td>中国B2C市场商标/版权保护</td></tr><tr><td>Amazon Brand Registry</td><td>平台工具（需备案）</td><td>Amazon平台品牌保护；Project Zero直接删除权；A+自动防护</td><td>亚马逊平台假冒品管理</td></tr><tr><td>TinEye</td><td>免费/付费工具</td><td>图像反向搜索；查找被盗用的产品图片</td><td>版权图片追踪</td></tr><tr><td>Spaceship/GoDaddy监控</td><td>域名服务附带功能</td><td>新注册与品牌相似域名的预警通知</td><td>品牌域名抢注防护</td></tr><tr><td>IPlytics</td><td>商业工具（付费）</td><td>专利地图；竞争对手专利申请动态监控</td><td>技术密集型行业专利战略</td></tr></tbody></table><h2 id="附录c-缩略词表" tabindex="-1">附录C　缩略词表 <a class="header-anchor" href="#附录c-缩略词表" aria-label="Permalink to &quot;附录C　缩略词表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>缩略词</th><th>英文全称</th><th>中文含义</th></tr></thead><tbody><tr><td>BOM</td><td>Bill of Materials</td><td>物料清单</td></tr><tr><td>CBP</td><td>US Customs and Border Protection</td><td>美国海关与边境保护局</td></tr><tr><td>CM</td><td>Contract Manufacturer</td><td>合同制造商</td></tr><tr><td>CIETAC</td><td>China International Economic and Trade Arbitration Commission</td><td>中国国际经济贸易仲裁委员会</td></tr><tr><td>CNIPA</td><td>China National Intellectual Property Administration</td><td>国家知识产权局（中国）</td></tr><tr><td>DTSA</td><td>Defend Trade Secrets Act (US)</td><td>美国《保护商业秘密法》</td></tr><tr><td>EUIPO</td><td>European Union Intellectual Property Office</td><td>欧盟知识产权局</td></tr><tr><td>FCPA</td><td>Foreign Corrupt Practices Act (US)</td><td>美国《海外反腐败法》</td></tr><tr><td>GI</td><td>Geographical Indication</td><td>地理标志</td></tr><tr><td>IP</td><td>Intellectual Property</td><td>知识产权</td></tr><tr><td>IPTF</td><td>IP Task Force</td><td>知识产权特别工作组</td></tr><tr><td>MSA</td><td>Master Supply Agreement</td><td>采购框架协议</td></tr><tr><td>NCA</td><td>Non-Compete Agreement</td><td>竞业限制协议</td></tr><tr><td>NDA</td><td>Non-Disclosure Agreement</td><td>保密协议</td></tr><tr><td>ODM</td><td>Original Design Manufacturer</td><td>原始设计制造商</td></tr><tr><td>OEM</td><td>Original Equipment Manufacturer</td><td>原始设备制造商</td></tr><tr><td>RMAP</td><td>Responsible Minerals Assurance Process</td><td>责任矿产保证流程</td></tr><tr><td>TLA</td><td>Trademark License Agreement</td><td>商标许可协议</td></tr><tr><td>TRIPS</td><td>Trade-Related Aspects of Intellectual Property Rights</td><td>与贸易有关的知识产权协定</td></tr><tr><td>UDRP</td><td>Uniform Domain-Name Dispute-Resolution Policy</td><td>域名争议统一解决政策（WIPO）</td></tr><tr><td>USPTO</td><td>US Patent and Trademark Office</td><td>美国专利商标局</td></tr><tr><td>VDR</td><td>Virtual Data Room</td><td>虚拟数据室</td></tr><tr><td>WIPO</td><td>World Intellectual Property Organization</td><td>世界知识产权组织</td></tr></tbody></table><h2 id="附录d-本指南中文关键术语简释" tabindex="-1">附录D　本指南中文关键术语简释 <a class="header-anchor" href="#附录d-本指南中文关键术语简释" aria-label="Permalink to &quot;附录D　本指南中文关键术语简释&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>英文对照</th><th>简释</th></tr></thead><tbody><tr><td>商标</td><td>Trademark / Trade Mark</td><td>用于区分商品/服务来源的可见标志；注册商标受法律明确保护，未注册商标依赖实际使用建立权利</td></tr><tr><td>专利</td><td>Patent</td><td>国家授予发明人的时限性独占权；公开换保护；分为发明专利、实用新型、外观设计三类（中国）</td></tr><tr><td>商业秘密</td><td>Trade Secret</td><td>不公开、有价值、采取了合理保密措施的商业信息；无需注册，保护期无限但须持续维护保密</td></tr><tr><td>监管链</td><td>Chain of Custody (CoC)</td><td>证明受认证材料或产品从认证源头到最终产品的完整追溯链；通过范围证书（SC）和交易证书（TC）实现</td></tr><tr><td>超产走私</td><td>Overrun / Unauthorized Production</td><td>授权代工厂在正常订单之外超量生产，利用同等物料/工具生产外观与正品相同的假冒品</td></tr><tr><td>平行进口</td><td>Gray Market / Parallel Import</td><td>真品通过未经授权的渠道流通，绕过品牌商的定价和区域分销体系；产品本身为真，渠道违规</td></tr><tr><td>序列化</td><td>Serialization</td><td>为每件产品/包装赋予唯一序列号，实现全链路追踪；是所有数字防伪和溯源技术的基础</td></tr><tr><td>化学标记物</td><td>Taggant</td><td>添加于材料中的微量化学/物理标记，需专用仪器读取；因成分保密，仿制难度极高</td></tr><tr><td>虚拟数据室</td><td>Virtual Data Room (VDR)</td><td>安全的在线文件共享环境，具有精细访问权限控制、下载限制和审计追踪功能；适用于高敏感度技术文件的有控制披露</td></tr></tbody></table><hr><h2 id="本指南配套模板" tabindex="-1">本指南配套模板 <a class="header-anchor" href="#本指南配套模板" aria-label="Permalink to &quot;本指南配套模板&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">直接可用的模板文件</p><p>以下模板与本指南内容直接对应，可在知识产权保护工作中直接使用：</p><table tabindex="0"><thead><tr><th>模板</th><th>适用本指南场景</th></tr></thead><tbody><tr><td><a href="/zh/templates/supplier-code.html">供应商行为准则（SCoC）§5 知识产权条款</a></td><td>供应商准入；合同附件</td></tr><tr><td><a href="/zh/templates/saq.html">供应商自评问卷 F节（IP保护）</a></td><td>年度IP评估</td></tr><tr><td><a href="/zh/templates/audit-checklist.html">审核前文件请求清单 四（IP合规）</a></td><td>现场审核前30天发出</td></tr><tr><td><a href="/zh/templates/interview-questions.html">访谈问题库：知识产权访谈</a></td><td>现场审核当天</td></tr><tr><td><a href="/zh/templates/forms.html#表单六知识产权事件报告表">知识产权事件报告表</a></td><td>发现IP事件时24小时内填报</td></tr><tr><td><a href="/zh/templates/forms.html#表单三整改行动计划cap">整改行动计划（CAP）</a></td><td>审核后发现项整改</td></tr></tbody></table></div>',155)])])}const c=d(h,[["render",i]]);export{u as __pageData,c as default};
